import React from 'react';
import AnimatedCounter from './AnimatedCounter';

const StatCard = ({ title, value, icon: Icon, color = 'blue', trend, prefix = '', suffix = '', description, className = '' }) => {
  const colors = {
    blue: 'from-blue-500 to-blue-600 text-blue-600 bg-blue-100',
    green: 'from-green-500 to-green-600 text-green-600 bg-green-100',
    purple: 'from-purple-500 to-purple-600 text-purple-600 bg-purple-100',
    orange: 'from-orange-500 to-orange-600 text-orange-600 bg-orange-100',
    yellow: 'from-yellow-500 to-yellow-600 text-yellow-600 bg-yellow-100'
  };

  const [gradient, textColor, iconBg] = colors[color].split(' ');

  return (
    <div className={`bg-white/80 backdrop-blur-sm rounded-2xl p-6 text-center border border-white/20 shadow-lg hover:shadow-xl transition-all duration-300 ${className}`}>
      <div className="flex items-center justify-between mb-4">
        <div className={`w-12 h-12 ${iconBg} rounded-xl flex items-center justify-center`}>
          <Icon className={`w-6 h-6 ${textColor}`} />
        </div>
        {trend && (
          <div className={`px-3 py-1 rounded-full text-xs font-semibold bg-${color}-50 ${textColor}`}>
            {trend > 0 ? '+' : ''}{trend}%
          </div>
        )}
      </div>
      <div className={`text-2xl font-bold mb-1 ${textColor}`}>
        <AnimatedCounter end={value} prefix={prefix} suffix={suffix} />
      </div>
      <div className="text-sm text-gray-600 mb-2">{title}</div>
      {description && <p className="text-xs text-gray-500">{description}</p>}
    </div>
  );
};

export default StatCard;
